def perceive(data):
    prices = {"bonds": 100.0, "gold": 100.0, "stocks": 100.0}
    for line in str(data).splitlines():
        line = line.strip()
        if not line or ':' not in line:
            continue
        name, val = line.split(':', 1)
        name = name.strip().lower()
        try:
            p = float(val.strip())
        except ValueError:
            continue
        if name in prices and p > 0:
            prices[name] = round(p, 6)
    return {"prices": prices}
